import React, { useState } from 'react';
import PatientRegistration from './components/PatientRegistration';
import QueueDisplay from './components/QueueDisplay';
import './App.css';

function App() {
  const [currentView, setCurrentView] = useState('queue'); // 'queue' or 'register'

  return (
    <div className="App">
      {/* Navigation */}
      <nav className="navbar">
        <div className="navbar-container">
          <div className="navbar-brand">🏥 Patient Queue</div>
          <div className="navbar-menu">
            <button
              className={`nav-btn ${currentView === 'queue' ? 'active' : ''}`}
              onClick={() => setCurrentView('queue')}
            >
              📋 Live Queue
            </button>
            <button
              className={`nav-btn ${currentView === 'register' ? 'active' : ''}`}
              onClick={() => setCurrentView('register')}
            >
              ➕ Register Patient
            </button>
          </div>
        </div>
      </nav>

      {/* Views */}
      <div className="view-container">
        {currentView === 'queue' && <QueueDisplay />}
        {currentView === 'register' && <PatientRegistration />}
      </div>
    </div>
  );
}

export default App;
